const dateFormatElements=document.getElementsByClassName("date-format");for(let e of dateFormatElements)try{e.innerHTML=luxon.DateTime.fromISO(e.innerHTML).toFormat("fff")}catch(e){console.error(e)}function openNav(){document.getElementById("side-navigation").style.width="250px"}function closeNav(){document.getElementById("side-navigation").style.width="0"}document.onkeyup=function(e){"Escape"==e.key&&(document.body.innerHTML="",location.href="https://taiko.bui.pm/")};